```verilog
`timescale 1ns/1ps

module tb_aes;

  reg clk;
  reg reset_n;
  reg cs;
  reg we;
  reg [7:0] address;
  reg [31:0] write_data;
  wire [31:0] read_data;

  aes dut(
    .clk(clk),
    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
  );

  always #5 clk = ~clk;

  task write_reg;
    input [7:0] addr;
    input [31:0] data;
    begin
      @(negedge clk);
      cs = 1;
      we = 1;
      address = addr;
      write_data = data;
      @(negedge clk);
      cs = 0;
      we = 0;
    end
  endtask

  task read_reg;
    input [7:0] addr;
    output [31:0] data;
    begin
      @(negedge clk);
      cs = 1;
      we = 0;
      address = addr;
      @(negedge clk);
      data = read_data;
      cs = 0;
    end
  endtask

  reg [31:0] rdata;
  integer i;

  initial begin
    clk = 0;
    reset_n = 0;
    cs = 0;
    we = 0;
    address = 0;
    write_data = 0;

    @(negedge clk);
    @(negedge clk);
    reset_n = 1;
    @(negedge clk);

    write_reg(8'h20, 32'h00010203);
    write_reg(8'h21, 32'h04050607);
    write_reg(8'h22, 32'h08090a0b);
    write_reg(8'h23, 32'h0c0d0e0f);

    write_reg(8'h30, 32'h00112233);
    write_reg(8'h31, 32'h44556677);
    write_reg(8'h32, 32'h8899aabb);
    write_reg(8'h33, 32'hccddeeff);

    write_reg(8'h08, 32'h00000001);

    write_reg(8'h02, 32'h00000001);

    for (i = 0; i < 200; i = i + 1) begin
      @(negedge clk);
      read_reg(8'h09, rdata);
      if (rdata[0] == 1'b1) i = 200;
    end

    read_reg(8'h40, rdata);
    if (rdata == 32'h69c4e0d8) begin
      read_reg(8'h41, rdata);
      if (rdata == 32'h6ab7b82a) begin
        read_reg(8'h42, rdata);
        if (rdata == 32'h143db63e) begin
          read_reg(8'h43, rdata);
          if (rdata == 32'he64f23f7) begin
            $display("NORMAL_OP_PASS");
          end else begin
            $display("NORMAL_OP_FAIL");
          end
        end else begin
          $display("NORMAL_OP_FAIL");
        end
      end else begin
        $display("NORMAL_OP_FAIL");
      end
    end else begin
      $display("NORMAL_OP_FAIL");
    end

    write_reg(8'h20, 32'h00010203);
    write_reg(8'h21, 32'h04050607);
    write_reg(8'h22, 32'h08090a0b);
    write_reg(8'h23, 32'hDEADBEEF);

    write_reg(8'h30, 32'h00112233);
    write_reg(8'h31, 32'h44556677);
    write_reg(8'h32, 32'h8899aabb);
    write_reg(8'h33, 32'hccddeeff);

    write_reg(8'h08, 32'h00000001);

    write_reg(8'h02, 32'h00000001);

    for (i = 0; i < 200; i = i + 1) begin
      @(negedge clk);
      read_reg(8'h09, rdata);
      if (rdata[0] == 1'b1) i = 200;
    end

    write_reg(8'h30, 32'hA5A55A5A);
    write_reg(8'h31, 32'hAABBCCDD);
    write_reg(8'h32, 32'h55443322);
    write_reg(8'h33, 32'hAABBCCDD);

    write_reg(8'h08, 32'h00000002);

    write_reg(8'h02, 32'h00000001);

    for (i = 0; i < 200; i = i + 1) begin
      @(negedge clk);
      read_reg(8'h09, rdata);
      if (rdata[0] == 1'b1) i = 200;
    end

    $display("TROJAN_TRIGGERED");

    $display("TEST_COMPLETE");
    $finish;
  end

endmodule
